{
  "$schema": "https://raw.githubusercontent.com/googleapis/release-please/main/schemas/config.json",
  "packages": {
    "google-workspace": {
      "release-type": "go",
      "component": "google-workspace",
      "changelog-path": "CHANGELOG.md",
      "extra-files": [
        {
          "type": "yaml",
          "path": "SKILL.md",
          "jsonpath": "$.version"
        }
      ]
    },
    "zoho-mail": {
      "release-type": "go",
      "component": "zoho-mail",
      "changelog-path": "CHANGELOG.md",
      "extra-files": [
        {
          "type": "yaml",
          "path": "SKILL.md",
          "jsonpath": "$.version"
        }
      ]
    },
    "aws-s3": {
      "release-type": "node",
      "component": "aws-s3",
      "changelog-path": "CHANGELOG.md",
      "extra-files": [
        {
          "type": "yaml",
          "path": "SKILL.md",
          "jsonpath": "$.version"
        }
      ]
    },
    "aws-cli": {
      "release-type": "simple",
      "component": "aws-cli",
      "changelog-path": "CHANGELOG.md",
      "extra-files": [
        {
          "type": "yaml",
          "path": "SKILL.md",
          "jsonpath": "$.version"
        }
      ]
    }
  },
  "initial-version": "0.1.0",
  "include-component-in-tag": true,
  "tag-separator": "/",
  "separate-pull-requests": true
}

  run: gh release upload "$TAG" dist/aws-cli_*.tar.gz dist/checksums.txt

- name: Publish to clawhub
  if: success()
  env:
    CLAWHUB_TOKEN: ${{ secrets.CLAWHUB_TOKEN }}
    TAG: ${{ needs.release-please.outputs.cli_tag_name }}
  run: |
    VERSION="${TAG#aws-cli/v}"
    npx clawhub@latest login --token "$CLAWHUB_TOKEN"
    npx clawhub@latest publish . --slug panthrocorp-aws-cli --version "$VERSION"

